from agent import *from models.products import *def run(context, session):    session.sessionbreakers = [SessionBreak(max_requests=6000)]    session.queue(Request("https://thehdroom.com/gaming/", use='curl'), process_revlist, dict())def process_revlist(data, context, session):    revs = data.xpath("//h2/a")    for rev in revs:        title = rev.xpath('text()').string()        url = rev.xpath("@href").string()        session.queue(Request(url, use='curl'), process_review, dict(context, url=url, title=title))    next_url = data.xpath('//a[contains(., "Older ")]/@href').string()    if next_url:        session.queue(Request(next_url, use='curl'), process_revlist, dict(context))def process_review(data, context, session):    product = Product()    product.name = context['title'].split("Review")[0].split("' ")[0].strip("'")    product.category = 'Gaming'    url = data.xpath('//p[contains(., "Source: ")]/a/@href').string()    if not url:        url = data.xpath('//a[contains(., "Purchase the")]/@href').string()    if not url:        url = data.xpath('//p[contains(., "Pre-order")][.//a]//@href').string()    if not url:        url = data.xpath('//a[contains(., "Learn more about")]/@href').string()    if not url:        url = data.xpath('//p[contains(., "Amazon.com")][.//a]//@href').string()    if not url:        url = data.xpath('//a[contains(., "Click here to")]/@href').string()    if not url:        url = context['url']    product.url = url    ssid = data.xpath('//article[contains(@id, "post")]/@id').string()    if ssid:        product.ssid = ssid.split('-')[-1]    else:        product.ssid = context["url"].split("/")[-2].split("-")[-1]    review = Review()    review.type = "pro"    review.title = context['title']    review.url = context['url']    review.ssid = product.ssid    date = data.xpath("//meta[@itemprop='datePublished']/@content").string()    if not date:        date = data.xpath('//meta[contains(@property, "published_time")]/@content').string()    if date:        review.date = date.split("T")[0]    author = data.xpath('//div[@class="author"]/a').first()    if author:        name = author.xpath("text()").string()        url = author.xpath("@href").string()        review.authors.append(Person(name=name, ssid=name, profile_url=url))    grade_overall = data.xpath('//div[@class="score"]/text()').string()    if grade_overall:        review.grades.append(Grade(type="overall", value=float(grade_overall), best=5.0))    excerpt = data.xpath('//div[@class="entry-content"]//p[not(contains(., "This review was based off"))][not(contains(., "This review is based on"))][not(contains(@id, "caption-attachment"))][not(.//a[contains(., "Purchase the")])][not(.//a[contains(., "Learn more about")])][not(self::p[contains(., "Source:")][.//a])][not(self::p[contains(., "Pre-order")][.//a])][not(self::p[contains(., "Click here to")][.//a])]//text()').string(multiple=True)    if excerpt:        review.add_property(type="excerpt", value=excerpt)        product.reviews.append(review)        session.emit(product)